o_date('20260331','YYYYMMDD') LEFT OUTER JOIN DIM_GAAP ON DIM_GAAP.N_GAAP_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_GAAP_SKEY INNER JOIN DIM_CAPITAL_COMP_GROUP ON DIM_CAPITAL_COMP_GROUP.N_CAP_COMP_GROUP_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_CAP_COMP_GROUP_SKEY AND DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE IN ( 'CET1COMP' ,'AT1COMP' ,'T2COMP' ) LEFT JOIN FCT_ENTITY_INFO ON FCT_ENTITY_INFO.N_PARTY_SKEY = COALESCE(FSI_CAP_INVESTMENT_EXPOSURES.N_ISSUER_SKEY, FSI_CAP_INVESTMENT_EXPOSURES.N_CUST_SKEY) AND FCT_ENTITY_INFO.N_RUN_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_RUN_SKEY AND FCT_ENTITY_INFO.N_GAAP_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_GAAP_SKEY AND FCT_ENTITY_INFO.N_MIS_DATE_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_MIS_DATE_SKEY AND COALESCE(FCT_ENTITY_INFO.F_REGULATORY_ENTITY_IND, 'N') = 'N' LEFT OUTER JOIN DIM_STANDARD_ACCT_HEAD ON DIM_STANDARD_ACCT_HEAD.N_STD_ACCT_HEAD_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_STD_ACCT_HEAD_SKEY WHERE FSI_CAP_INVESTMENT_EXPOSURES.F_SIGNIFICANT_INVESTMENT_IND = 'N' AND COALESCE(FSI_CAP_INVESTMENT_EXPOSURES.F_SUPERVISORY_DED_EXCLUSION, 'N') = 'N' AND ( ( DIM_RUN.V_JURISDICTION_CODE = 'THAI' AND ( DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID NOT IN ( 'CAP1187' ,'CAP1190' ,'CAP1193' ) OR DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID IS NULL ) /*BOT*/ ) OR DIM_RUN.V_JURISDICTION_CODE != 'THAI' ) GROUP BY FSI_CAP_INVESTMENT_EXPOSURES.N_RUN_SKEY ,FSI_CAP_INVESTMENT_EXPOSURES.N_GAAP_SKEY ,FSI_CAP_INVESTMENT_EXPOSURES.N_MIS_DATE_SKEY ,FSI_CAP_INVESTMENT_EXPOSURES.F_SIGNIFICANT_INVESTMENT_IND ,COALESCE(FSI_CAP_INVESTMENT_EXPOSURES.N_ISSUER_SKEY, FSI_CAP_INVESTMENT_EXPOSURES.N_CUST_SKEY) /* UNION ALL SELECT FSI_CAP_DERIVATIVES.N_RUN_SKEY N_RUN_SKEY ,FSI_CAP_DERIVATIVES.N_GAAP_SKEY N_GAAP_SKEY ,FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY N_MIS_DATE_SKEY ,FSI_CAP_DERIVATIVES.F_SIGNIFICANT_INVESTMENT_IND F_SIGNIFICANT_INVESTMENT_IND ,SUM(COALESCE(FSI_CAP_DERIVATIVES.N_EAD_PRE_MITIGATION, 0)) TOTAL_EXP_AMOUNT ,FSI_CAP_DERIVATIVES.N_CUST_SKEY N_PARTY_SKEY ,SUM ( CASE WHEN DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE = 'CET1COMP' THEN COALESCE(FSI_CAP_DERIVATIVES.N_EAD_PRE_MITIGATION, 0) ELSE 0 END ) N_CET1_INVST ,SUM ( CASE WHEN DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE = 'AT1COMP' THEN COALESCE(FSI_CAP_DERIVATIVES.N_EAD_PRE_MITIGATION, 0) ELSE 0 END ) N_AT1_INVST ,SUM ( CASE WHEN DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE = 'T2COMP' THEN COALESCE(FSI_CAP_DERIVATIVES.N_EAD_PRE_MITIGATION, 0) ELSE 0 END ) N_T2_INVST FROM FSI_CAP_DERIVATIVES INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = FSI_CAP_DERIVATIVES.N_RUN_SKEY AND DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_DATES ON DIM_DATES.N_DATE_SKEY = FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') LEFT OUTER JOIN DIM_GAAP ON DIM_GAAP.N_GAAP_SKEY = FSI_CAP_DERIVATIVES.N_GAAP_SKEY INNER JOIN DIM_CAPITAL_COMP_GROUP ON DIM_CAPITAL_COMP_GROUP.N_CAP_COMP_GROUP_SKEY = FSI_CAP_DERIVATIVES.N_CAP_COMP_GROUP_SKEY AND DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE IN ( 'CET1COMP' ,'AT1COMP' ,'T2COMP' ) LEFT JOIN FCT_ENTITY_INFO ON FCT_ENTITY_INFO.N_PARTY_SKEY = FSI_CAP_DERIVATIVES.N_CUST_SKEY AND FCT_ENTITY_INFO.N_RUN_SKEY = FSI_CAP_DERIVATIVES.N_RUN_SKEY AND FCT_ENTITY_INFO.N_GAAP_SKEY = FSI_CAP_DERIVATIVES.N_GAAP_SKEY AND FCT_ENTITY_INFO.N_MIS_DATE_SKEY = FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY AND COALESCE(FCT_ENTITY_INFO.F_REGULATORY_ENTITY_IND, 'N') = 'N' LEFT OUTER JOIN DIM_STANDARD_ACCT_HEAD ON DIM_STANDARD_ACCT_HEAD.N_STD_ACCT_HEAD_SKEY = FSI_CAP_DERIVATIVES.N_STD_ACCT_HEAD_SKEY WHERE FSI_CAP_DERIVATIVES.F_SIGNIFICANT_INVESTMENT_IND = 'N' AND COALESCE(FSI_CAP_DERIVATIVES.F_SUPERVISORY_DED_EXCLUSION, 'N') = 'N' AND ( ( DIM_RUN.V_JURISDICTION_CODE = 'THAI' AND ( DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID NOT IN ( 'CAP1187' ,'CAP1190' ,'CAP1193' ) OR DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID IS NULL )  ) OR DIM_RUN.V_JURISDICTION_CODE != 'THAI' ) GROUP BY FSI_CAP_DERIVATIVES.N_RUN_SKEY ,FSI_CAP_DERIVATIVES.N_GAAP_SKEY ,FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY ,FSI_CAP_DERIVATIVES.F_SIGNIFICANT_INVESTMENT_IND ,FSI_CAP_DERIVATIVES.N_CUST_SKEY*/ UNION ALL SELECT FCT_MARKET_RISK_EXPOSURES.N_RUN_SKEY N_RUN_SKEY ,FCT_MARKET_RISK_EXPOSURES.N_GAAP_SKEY N_GAAP_SKEY ,FCT_MARKET_RISK_EXPOSURES.N_MIS_DATE_SKEY N_MIS_DATE_SKEY ,FCT_MARKET_RISK_EXPOSURES.F_SIGNIFICANT_INVESTMENT_IND F_SIGNIFICANT_INVESTMENT_IND ,SUM(COALESCE(FCT_MARKET_RISK_EXPOSURES.N_NOTIONAL_AMT, 0)) TOTAL_EXP_AMOUNT ,COALESCE(FCT_MARKET_RISK_EXPOSURES.N_ISSUER_SKEY, FCT_MARKET_RISK_EXPOSURES.N_CUST_SKEY) N_PARTY_SKEY ,SUM ( CASE WHEN DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE = 'CET1COMP' THEN COALESCE(FCT_MARKET_RISK_EXPOSURES.N_NOTIONAL_AMT, 0) ELSE 0 END ) N_CET1_INVST ,SUM ( CASE WHEN DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE = 'AT1COMP' THEN COALESCE(FCT_MARKET_RISK_EXPOSURES.N_NOTIONAL_AMT, 0) ELSE 0 END ) N_AT1_INVST ,SUM ( CASE WHEN DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE = 'T2COMP' THEN COALESCE(FCT_MARKET_RISK_EXPOSURES.N_NOTIONAL_AMT, 0) ELSE 0 END ) N_T2_INVST FROM FCT_MARKET_RISK_EXPOSURES  LEFT JOIN DIM_INSTRUMENT_CONTRACT ON DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY = FCT_MARKET_RISK_EXPOSURES.N_INSTRUMENT_SKEY AND DIM_INSTRUMENT_CONTRACT.F_LATEST_RECORD_INDICATOR = 'Y' INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = FCT_MARKET_RISK_EXPOSURES.N_RUN_SKEY AND DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_DATES ON DIM_DATES.N_DATE_SKEY = FCT_MARKET_RISK_EXPOSURES.N_MIS_DATE_SKEY AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') LEFT OUTER JOIN DIM_GAAP ON DIM_GAAP.N_GAAP_SKEY = FCT_MARKET_RISK_EXPOSURES.N_GAAP_SKEY INNER JOIN DIM_CAPITAL_COMP_GROUP ON DIM_CAPITAL_COMP_GROUP.N_CAP_COMP_GROUP_SKEY = FCT_MARKET_RISK_EXPOSURES.N_CAP_COMP_GROUP_SKEY AND DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE IN ( 'CET1COMP' ,'AT1COMP' ,'T2COMP' ) LEFT JOIN FCT_ENTITY_INFO ON FCT_ENTITY_INFO.N_PARTY_SKEY = COALESCE(FCT_MARKET_RISK_EXPOSURES.N_ISSUER_SKEY, FCT_MARKET_RISK_EXPOSURES.N_CUST_SKEY) AND FCT_ENTITY_INFO.N_RUN_SKEY = FCT_MARKET_RISK_EXPOSURES.N_RUN_SKEY AND FCT_ENTITY_INFO.N_GAAP_SKEY = FCT_MARKET_RISK_EXPOSURES.N_GAAP_SKEY AND FCT_ENTITY_INFO.N_MIS_DATE_SKEY = FCT_MARKET_RISK_EXPOSURES.N_MIS_DATE_SKEY AND COALESCE(FCT_ENTITY_INFO.F_REGULATORY_ENTITY_IND, 'N') = 'N' WHERE FCT_MARKET_RISK_EXPOSURES.F_SIGNIFICANT_INVESTMENT_IND = 'N' AND DIM_INSTRUMENT_CONTRACT.V_INSTR_TYPE_CODE NOT IN ('MFNDEQT', 'MFNDCASH') GROUP BY FCT_MARKET_RISK_EXPOSURES.N_RUN_SKEY ,FCT_MARKET_RISK_EXPOSURES.N_GAAP_SKEY ,FCT_MARKET_RISK_EXPOSURES.N_MIS_DATE_SKEY ,FCT_MARKET_RISK_EXPOSURES.F_SIGNIFICANT_INVESTMENT_IND ,COALESCE(FCT_MARKET_RISK_EXPOSURES.N_ISSUER_SKEY, FCT_MARKET_RISK_EXPOSURES.N_CUST_SKEY)) NON_REG_INVST_EXPOSURES LEFT OUTER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = NON_REG_INVST_EXPOSURES.N_RUN_SKEY LEFT OUTER JOIN DIM_DATES ON DIM_DATES.N_DATE_SKEY = NON_REG_INVST_EXPOSURES.N_MIS_DATE_SKEY LEFT OUTER JOIN DIM_GAAP ON DIM_GAAP.N_GAAP_SKEY = NON_REG_INVST_EXPOSURES.N_GAAP_SKEY LEFT OUTER JOIN ( SELECT FCT_STANDARD_ACCT_HEAD.N_RUN_SKEY ,FCT_STANDARD_ACCT_HEAD.N_MIS_DATE_SKEY ,FCT_STANDARD_ACCT_HEAD.N_GAAP_SKEY ,FCT_STANDARD_ACCT_HEAD.N_STD_ACCT_HEAD_AMT FROM FCT_STANDARD_ACCT_HEAD LEFT OUTER JOIN DIM_STANDARD_ACCT_HEAD ON DIM_STANDARD_ACCT_HEAD.N_STD_ACCT_HEAD_SKEY = FCT_STANDARD_ACCT_HEAD.N_STD_ACCT_HEAD_SKEY WHERE FCT_STANDARD_ACCT_HEAD.N_RUN_SKEY = '870' /*AND FCT_STANDARD_ACCT_HEAD.FIC_MIS_DATE = to_date('20260331','YYYYMMDD')*/ AND DIM_STANDARD_ACCT_HEAD.V_STD_ACCT_HEAD_ID = 'CAP896' ) STD_ACCT_HEAD ON STD_ACCT_HEAD.N_RUN_SKEY = NON_REG_INVST_EXPOSURES.N_RUN_SKEY AND STD_ACCT_HEAD.N_MIS_DATE_SKEY = NON_REG_INVST_EXPOSURES.N_MIS_DATE_SKEY AND STD_ACCT_HEAD.N_GAAP_SKEY = NON_REG_INVST_EXPOSURES.N_GAAP_SKEY LEFT OUTER JOIN FCT_ENTITY_INFO FCT_ENTITY_INFO_PARENT on FCT_ENTITY_INFO_PARENT.N_RUN_SKEY = '870' AND FCT_ENTITY_INFO_PARENT.n_Mis_Date_Skey = DIM_DATES.N_DATE_SKEY AND FCT_ENTITY_INFO_PARENT.F_CAP_CONSL_PARENT_ENTITY_IND = 'Y' AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') WHERE 1=1 AND DIM_RUN.N_RUN_SKEY = '870' AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') GROUP BY DIM_RUN.N_RUN_SKEY, DIM_GAAP.N_GAAP_SKEY, DIM_DATES.N_DATE_SKEY, NON_REG_INVST_EXPOSURES.F_SIGNIFICANT_INVESTMENT_IND, NON_REG_INVST_EXPOSURES.N_PARTY_SKEY,FCT_ENTITY_INFO_PARENT.N_ENTITY_SKEY LOG ERRORS INTO FSI_NON_REG_CONSL_ENTITY_INVS$ ('1776771336831_66936885_20260331_1_Job_1b1c761fcbea4fb9bb02c1879a0dd6f8') REJECT LIMIT UNLIMITED;

